"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[7872],{54245:(e,i,n)=>{n.r(i),n.d(i,{data:()=>l});const l={key:"v-eed95fe6",path:"/%E5%89%8D%E7%AB%AF/%E9%A3%8E%E6%A0%BC%E6%8C%87%E5%8D%97.html",title:"前端风格指南",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"一、命名规范",slug:"一、命名规范",children:[{level:3,title:"1.1 项目文件命名",slug:"_1-1-项目文件命名",children:[]},{level:3,title:"1.2 Vue 组件命名",slug:"_1-2-vue-组件命名",children:[]},{level:3,title:"1.3 代码参数命名",slug:"_1-3-代码参数命名",children:[]}]},{level:2,title:"二、代码规范",slug:"二、代码规范",children:[{level:3,title:"2.1 Vue2",slug:"_2-1-vue2",children:[]},{level:3,title:"2.2 Vue3",slug:"_2-2-vue3",children:[]},{level:3,title:"2.3 HTML",slug:"_2-3-html",children:[]},{level:3,title:"2.4 CSS",slug:"_2-4-css",children:[]},{level:3,title:"2.4 JavaScript",slug:"_2-4-javascript",children:[]}]},{level:2,title:"三、注释规范",slug:"三、注释规范",children:[{level:3,title:"3.1 HTML 文件注释",slug:"_3-1-html-文件注释",children:[]},{level:3,title:"3.2 CSS 文件注释",slug:"_3-2-css-文件注释",children:[]},{level:3,title:"3.3 JavaScript 文件注释",slug:"_3-3-javascript-文件注释",children:[]}]},{level:2,title:"参考资料",slug:"参考资料",children:[]}],git:{updatedTime:1657530467e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:2}]},filePathRelative:"前端/风格指南.md"}},84946:(e,i,n)=>{n.r(i),n.d(i,{default:()=>d});const l=(0,n(57293).uE)('<h1 id="前端风格指南" tabindex="-1"><a class="header-anchor" href="#前端风格指南" aria-hidden="true">#</a> 前端风格指南</h1><h2 id="一、命名规范" tabindex="-1"><a class="header-anchor" href="#一、命名规范" aria-hidden="true">#</a> 一、命名规范</h2><p>市面上常用的命名规范：</p><ul><li><code>camelCase</code>（小驼峰式命名法 —— 首字母小写）</li><li><code>PascalCase</code>（大驼峰式命名法 —— 首字母大写）</li><li><code>kebab-case</code>（短横线连接式）</li><li><code>Snake</code>（下划线连接式）</li></ul><h3 id="_1-1-项目文件命名" tabindex="-1"><a class="header-anchor" href="#_1-1-项目文件命名" aria-hidden="true">#</a> 1.1 项目文件命名</h3><h4 id="_1-1-1-项目名" tabindex="-1"><a class="header-anchor" href="#_1-1-1-项目名" aria-hidden="true">#</a> 1.1.1 项目名</h4><p>全部采用小写方式， 以<strong>短横线</strong>分隔。例：<code>my-project-name</code>。</p><h4 id="_1-1-2-目录名" tabindex="-1"><a class="header-anchor" href="#_1-1-2-目录名" aria-hidden="true">#</a> 1.1.2 目录名</h4><p><strong>参照项目命名规则，有复数结构时，要采用复数命名法</strong>。例：docs、assets、components、directives、mixins、utils、views。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>my-project-name/\n|- BuildScript    // 流水线部署文件目录\n|- docs           // 项目的细化文档目录（可选）\n|- nginx          // 部署在容器上前端项目 nginx 代理文件目录\n|- node_modules   // 下载的依赖包\n|- public         // 静态页面目录\n    |- index.html // 项目入口\n|- src            // 源码目录\n    |- api        // http 请求目录\n    |- assets     // 静态资源目录，这里的资源会被wabpack构建\n        |- icon   // icon 存放目录\n        |- img    // 图片存放目录\n        |- js     // 公共 js 文件目录\n        |- scss   // 公共样式 scss 存放目录\n            |- frame.scss   // 入口文件\n            |- global.scss  // 公共样式\n            |- reset.scss   // 重置样式\n    |- components     // 组件\n    |- plugins        // 插件\n    |- router         // 路由\n    |- routes         // 详细的路由拆分目录（可选）\n        |- index.js\n    |- store          // 全局状态管理\n    |- utils          // 工具存放目录\n        |- request.js // 公共请求工具\n    |- views          // 页面存放目录\n    |- App.vue        // 根组件\n    |- main.js        // 入口文件\n|- tests          // 测试用例\n|- .browserslistrc// 浏览器兼容配置文件\n|- .editorconfig  // 编辑器配置文件\n|- .eslintignore  // eslint 忽略规则\n|- .eslintrc.js   // eslint 规则\n|- .gitignore     // git 忽略规则\n|- babel.config.js // babel 规则\n|- Dockerfile // Docker 部署文件\n|- jest.config.js\n|- package-lock.json\n|- package.json // 依赖\n|- README.md // 项目 README\n|- vue.config.js // webpack 配置\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-1-3-图像文件名" tabindex="-1"><a class="header-anchor" href="#_1-1-3-图像文件名" aria-hidden="true">#</a> 1.1.3 图像文件名</h4><p>全部采用小写方式， 优先选择单个单词命名，多个单词命名以<strong>下划线</strong>分隔。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>banner_sina.gif\nmenu_aboutus.gif\nmenutitle_news.gif\nlogo_police.gif\nlogo_national.gif\npic_people.jpg\npic_TV.jpg\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-1-4-html-文件名" tabindex="-1"><a class="header-anchor" href="#_1-1-4-html-文件名" aria-hidden="true">#</a> 1.1.4 HTML 文件名</h4><p>全部采用小写方式， 优先选择单个单词命名，多个单词命名以<strong>下划线</strong>分隔。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>|- error_report.html\n|- success_report.html\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-1-5-css-文件名" tabindex="-1"><a class="header-anchor" href="#_1-1-5-css-文件名" aria-hidden="true">#</a> 1.1.5 CSS 文件名</h4><p>全部采用小写方式， 优先选择单个单词命名，多个单词命名以<strong>短横线</strong>分隔。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>|- normalize.less\n|- base.less\n|- date-picker.scss\n|- input-number.scss\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-1-6-javascript-文件名" tabindex="-1"><a class="header-anchor" href="#_1-1-6-javascript-文件名" aria-hidden="true">#</a> 1.1.6 JavaScript 文件名</h4><p>全部采用小写方式， 优先选择单个单词命名，多个单词命名以<strong>短横线</strong>分隔。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>|- index.js\n|- plugin.js\n|- util.js\n|- date-util.js\n|- account-model.js\n|- collapse-transition.js\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>上述规则可以快速记忆为“静态文件下划线，编译文件短横线”。</p></blockquote><h3 id="_1-2-vue-组件命名" tabindex="-1"><a class="header-anchor" href="#_1-2-vue-组件命名" aria-hidden="true">#</a> 1.2 Vue 组件命名</h3><h4 id="_1-2-1-单文件组件名" tabindex="-1"><a class="header-anchor" href="#_1-2-1-单文件组件名" aria-hidden="true">#</a> 1.2.1 单文件组件名</h4><p>文件扩展名为 <code>.vue</code> 的 <code>single-file components</code> (单文件组件)。单文件组件名应该始终是<strong>单词大写开头</strong> (PascalCase)。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>components/\n|- MyComponent.vue\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-2-2-单例组件名" tabindex="-1"><a class="header-anchor" href="#_1-2-2-单例组件名" aria-hidden="true">#</a> 1.2.2 单例组件名</h4><p><strong>只拥有单个活跃实例的组件应该以 <code>The</code> 前缀命名，以示其唯一性。</strong></p><p>这不意味着组件只可用于一个单页面，而是_每个页面_只使用一次。这些组件永远不接受任何 prop，因为它们是为你的应用定制的。如果你发现有必要添加 prop，那就表明这实际上是一个可复用的组件，_只是目前_在每个页面里只使用一次。</p><p>比如，头部和侧边栏组件几乎在每个页面都会使用，不接受 prop，该组件是专门为该应用所定制的。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>components/\n|- TheHeading.vue\n|- TheSidebar.vue\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-2-3-基础组件名" tabindex="-1"><a class="header-anchor" href="#_1-2-3-基础组件名" aria-hidden="true">#</a> 1.2.3 基础组件名</h4><p>基础组件：不包含业务，独立、具体功能的基础组件，比如<strong>日期选择器</strong>、<strong>模态框</strong>等。这类组件作为项目的基础控件，会被大量使用，因此组件的 API 进行过高强度的抽象，可以通过不同配置实现不同的功能。</p><p>应用特定样式和约定的基础组件(也就是展示类的、无逻辑的或无状态、不掺杂业务逻辑的组件) 应该全部以一个特定的前缀开头 —— Base。<strong>基础组件在一个页面内可使用多次，在不同页面内也可复用，是高可复用组件。</strong></p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>components/\n|- BaseButton.vue\n|- BaseTable.vue\n|- BaseIcon.vue\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-2-4-业务组件" tabindex="-1"><a class="header-anchor" href="#_1-2-4-业务组件" aria-hidden="true">#</a> 1.2.4 业务组件</h4><p>业务组件：它不像基础组件只包含某个功能，而是在业务中被多个页面复用的（具有可复用性），它与基础组件的区别是，业务组件只在当前项目中会用到，不具有通用性，而且会包含一些业务，比如数据请求；而基础组件不含业务，在任何项目中都可以使用，功能单一，比如一个具有数据校验功能的输入框。</p><p><strong>掺杂了复杂业务的组件（拥有自身 <code>data</code>、<code>prop</code> 的相关处理）即业务组件</strong>应该以 <code>Custom</code> 前缀命名。业务组件在一个页面内比如：某个页面内有一个卡片列表，而样式和逻辑跟业务紧密相关的卡片就是业务组件。</p><h4 id="_1-2-5-紧密耦合的组件名" tabindex="-1"><a class="header-anchor" href="#_1-2-5-紧密耦合的组件名" aria-hidden="true">#</a> 1.2.5 紧密耦合的组件名</h4><p><strong>和父组件紧密耦合的子组件应该以父组件名作为前缀命名。</strong> 因为编辑器通常会按字母顺序组织文件，所以这样做可以把相关联的文件排在一起。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>components/\n|- TodoList.vue\n|- TodoListItem.vue\n|- TodoListItemButton.vue\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-2-6-组件名中单词顺序" tabindex="-1"><a class="header-anchor" href="#_1-2-6-组件名中单词顺序" aria-hidden="true">#</a> 1.2.6 组件名中单词顺序</h4><p><strong>组件名应该以高级别的 (通常是一般化描述的) 单词开头，以描述性的修饰词结尾。</strong> 因为编辑器通常会按字母顺序组织文件，所以现在组件之间的重要关系一目了然。如下组件主要是用于搜索和设置功能。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>components/\n|- SearchButtonClear.vue\n|- SearchButtonRun.vue\n|- SearchInputQuery.vue\n|- SearchInputExcludeGlob.vue\n|- SettingsCheckboxTerms.vue\n|- SettingsCheckboxLaunchOnStartup.vue\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>还有另一种多级目录的方式，把所有的搜索组件放到“search”目录，把所有的设置组件放到“settings”目录。我们只推荐在非常大型 (如有 100+ 个组件) 的应用下才考虑这么做，因为在多级目录间找来找去，要比在单个 components 目录下滚动查找要花费更多的精力。</p><h4 id="_1-2-7-完整单词的组件名" tabindex="-1"><a class="header-anchor" href="#_1-2-7-完整单词的组件名" aria-hidden="true">#</a> 1.2.7 完整单词的组件名</h4><p><strong>组件名应该倾向于而不是缩写。</strong> 编辑器中的自动补全已经让书写长命名的代价非常之低了，而其带来的明确性却是非常宝贵的。不常用的缩写尤其应该避免。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>components/\n|- StudentDashboardSettings.vue\n|- UserProfileOptions.vue\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-3-代码参数命名" tabindex="-1"><a class="header-anchor" href="#_1-3-代码参数命名" aria-hidden="true">#</a> 1.3 代码参数命名</h3><h4 id="_1-3-1-name" tabindex="-1"><a class="header-anchor" href="#_1-3-1-name" aria-hidden="true">#</a> 1.3.1 name</h4><p><strong>组件名应该始终是多个单词，应该始终是 PascalCase 的。</strong> 根组件 App 以及 <code>&lt;transition&gt;</code>、<code>&lt;component&gt;</code> 之类的 Vue 内置组件除外。这样做可以避免跟现有的以及未来的 HTML 元素相冲突，因为所有的 HTML 元素名称都是单个单词的。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>export default {\n  name: &#39;ToDoList&#39;,\n  // ...\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-3-2-prop" tabindex="-1"><a class="header-anchor" href="#_1-3-2-prop" aria-hidden="true">#</a> 1.3.2 prop</h4><p><strong>在声明 prop 的时候，其命名应该始终使用 camelCase，而在模板和 JSX 中应该始终使用 kebab-case</strong>。我们单纯的遵循每个语言的约定，在 JavaScript 中更自然的是 camelCase。而在 HTML 中则是 kebab-case。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;WelcomeMessage greeting-text=&quot;hi&quot;/&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>export default {\n  name: &#39;MyComponent&#39;,\n  // ...\n  props: {\n    greetingText: {\n      type: String,\n      required: true,\n      validator: function (value) {\n        return [&#39;syncing&#39;, &#39;synced&#39;,].indexOf(value) !== -1\n      }\n    }\n  }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-3-3-router" tabindex="-1"><a class="header-anchor" href="#_1-3-3-router" aria-hidden="true">#</a> 1.3.3 router</h4><p><strong>Vue Router Path 命名采用 kebab-case 格式。</strong> 用 Snake（如：<code>/user_info</code>）或 camelCase（如：<code>/userInfo</code>)的单词会被当成一个单词，搜索引擎无法区分语义。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// bad\n{\n  path: &#39;/user_info&#39;, // user_info 当成一个单词\n  name: &#39;UserInfo&#39;,\n  component: UserInfo,\n  meta: {\n    title: &#39; - 用户&#39;,\n    desc: &#39;&#39;\n  }\n},\n\n// good\n{\n  path: &#39;/user-info&#39;, // 能解析成 user info\n  name: &#39;UserInfo&#39;,\n  component: UserInfo,\n  meta: {\n    title: &#39; - 用户&#39;,\n    desc: &#39;&#39;\n  }\n},\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-3-4-模板中组件" tabindex="-1"><a class="header-anchor" href="#_1-3-4-模板中组件" aria-hidden="true">#</a> 1.3.4 模板中组件</h4><p><strong>对于绝大多数项目来说，在单文件组件和字符串模板中组件名应该总是 PascalCase 的，但是在 DOM 模板中总是 kebab-case 的。</strong></p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- 在单文件组件和字符串模板中 --&gt; \n&lt;MyComponent/&gt;\n\n&lt;!-- 在 DOM 模板中 --&gt; \n&lt;my-component&gt;&lt;/my-component&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-3-5-自闭合组件" tabindex="-1"><a class="header-anchor" href="#_1-3-5-自闭合组件" aria-hidden="true">#</a> 1.3.5 自闭合组件</h4><p><strong>在单文件组件、字符串模板和 JSX 中没有内容的组件应该是自闭合的——但在 DOM 模板里永远不要这样做。</strong></p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- 在单文件组件和字符串模板中 --&gt;\n&lt;MyComponent/&gt;\n\n&lt;!-- 在所有地方 --&gt;\n&lt;my-component&gt;&lt;/my-component&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-3-6-变量" tabindex="-1"><a class="header-anchor" href="#_1-3-6-变量" aria-hidden="true">#</a> 1.3.6 变量</h4><ul><li>命名方法：camelCase</li><li>命名规范：类型 + 对象描述或属性的方式</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// bad\nvar getTitle = &quot;LoginTable&quot;\n\n// good\nlet tableTitle = &quot;LoginTable&quot;\nlet mySchool = &quot;我的学校&quot;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-3-7-常量" tabindex="-1"><a class="header-anchor" href="#_1-3-7-常量" aria-hidden="true">#</a> 1.3.7 常量</h4><ul><li>命名方法：全部大写下划线分割</li><li>命名规范：使用大写字母和下划线来组合命名，下划线用以分割单词</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>const MAX_COUNT = 10\nconst URL = &#39;http://test.host.com&#39;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-3-8-方法" tabindex="-1"><a class="header-anchor" href="#_1-3-8-方法" aria-hidden="true">#</a> 1.3.8 方法</h4><ul><li>命名方法：camelCase</li><li>命名规范：统一使用动词或者动词 + 名词形式</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// 1、普通情况下，使用动词 + 名词形式\n// bad\ngo、nextPage、show、open、login\n\n// good\njumpPage、openCarInfoDialog\n\n// 2、请求数据方法，以 data 结尾\n// bad\ntakeData、confirmData、getList、postForm\n\n// good\ngetListData、postFormData\n\n// 3、单个动词的情况\ninit、refresh\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th style="text-align:left;">动词</th><th style="text-align:left;">含义</th><th style="text-align:left;">返回值</th></tr></thead><tbody><tr><td style="text-align:left;">can</td><td style="text-align:left;">判断是否可执行某个动作 (权 )</td><td style="text-align:left;">函数返回一个布尔值。true：可执行；false：不可执行；</td></tr><tr><td style="text-align:left;">has</td><td style="text-align:left;">判断是否含有某个值</td><td style="text-align:left;">函数返回一个布尔值。true：含有此值；false：不含有此值；</td></tr><tr><td style="text-align:left;">is</td><td style="text-align:left;">判断是否为某个值</td><td style="text-align:left;">函数返回一个布尔值。true：为某个值；false：不为某个值；</td></tr><tr><td style="text-align:left;">get</td><td style="text-align:left;">获取某个值</td><td style="text-align:left;">函数返回一个非布尔值</td></tr><tr><td style="text-align:left;">set</td><td style="text-align:left;">设置某个值</td><td style="text-align:left;">无返回值、返回是否设置成功或者返回链式对象</td></tr></tbody></table><h4 id="_1-3-9-自定义事件" tabindex="-1"><a class="header-anchor" href="#_1-3-9-自定义事件" aria-hidden="true">#</a> 1.3.9 自定义事件</h4><p><strong>自定义事件应始终使用 kebab-case 的事件名。</strong></p><p>不同于组件和 prop，事件名不存在任何自动化的大小写转换。而是触发的事件名需要完全匹配监听这个事件所用的名称。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>this.$emit(&#39;my-event&#39;)\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;MyComponent @my-event=&quot;handleDoSomething&quot; /&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>不同于组件和 prop，事件名不会被用作一个 JavaScript 变量名或 property 名，所以就没有理由使用 camelCase 或 PascalCase 了。并且 <code>v-on</code> 事件监听器在 DOM 模板中会被自动转换为全小写 (因为 HTML 是大小写不敏感的)，所以 <code>v-on:myEvent</code> 将会变成 <code>v-on:myevent</code>——导致 <code>myEvent</code> 不可能被监听到。</p><ul><li><strong>原生事件参考列表</strong>[1]</li></ul><p>由原生事件可以发现其使用方式如下：</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;div\n  @blur=&quot;toggleHeaderFocus&quot;\n  @focus=&quot;toggleHeaderFocus&quot;\n  @click=&quot;toggleMenu&quot;\n  @keydown.esc=&quot;handleKeydown&quot;\n  @keydown.enter=&quot;handleKeydown&quot;\n  @keydown.up.prevent=&quot;handleKeydown&quot;\n  @keydown.down.prevent=&quot;handleKeydown&quot;\n  @keydown.tab=&quot;handleKeydown&quot;\n  @keydown.delete=&quot;handleKeydown&quot;\n  @mouseenter=&quot;hasMouseHoverHead = true&quot;\n  @mouseleave=&quot;hasMouseHoverHead = false&quot;&gt;\n&lt;/div&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>而为了区分_原生事件_和_自定义事件_在 Vue 中的使用，建议除了多单词事件名使用 kebab-case 的情况下，命名还需遵守为 <strong><code>on</code> + 动词</strong> 的形式，如下：</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- 父组件 --&gt;\n&lt;div\n @on-search=&quot;handleSearch&quot;\n @on-clear=&quot;handleClear&quot;\n @on-clickoutside=&quot;handleClickOutside&quot;&gt;\n&lt;/div&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// 子组件\nexport default {\n methods: {\n  handleTriggerItem () {\n   this.$emit(&#39;on-clear&#39;)\n  }\n }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_1-3-10-事件方法" tabindex="-1"><a class="header-anchor" href="#_1-3-10-事件方法" aria-hidden="true">#</a> 1.3.10 事件方法</h4><ul><li>命名方法：camelCase</li><li>命名规范：handle + 名称（可选）+ 动词</li></ul><div class="language-vue ext-vue line-numbers-mode"><pre class="language-vue"><code>&lt;template&gt;\n  &lt;div\n    @click.native.stop=&quot;handleItemClick()&quot;\n    @mouseenter.native.stop=&quot;handleItemHover()&quot;&gt;\n  &lt;/div&gt;\n&lt;/template&gt;\n\n&lt;script&gt;\n\nexport default {\n  methods: {\n    handleItemClick () {\n      //...\n    },\n    handleItemHover () {\n      //...\n    }\n  }\n}\n&lt;/script&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="二、代码规范" tabindex="-1"><a class="header-anchor" href="#二、代码规范" aria-hidden="true">#</a> 二、代码规范</h2><h3 id="_2-1-vue2" tabindex="-1"><a class="header-anchor" href="#_2-1-vue2" aria-hidden="true">#</a> 2.1 Vue2</h3><h4 id="_2-1-1-代码结构" tabindex="-1"><a class="header-anchor" href="#_2-1-1-代码结构" aria-hidden="true">#</a> 2.1.1 代码结构</h4><div class="language-vue ext-vue line-numbers-mode"><pre class="language-vue"><code>&lt;template&gt;\n  &lt;div id=&quot;my-component&quot;&gt;\n    &lt;DemoComponent /&gt;\n  &lt;/div&gt;\n&lt;/template&gt;\n\n&lt;script&gt;\nimport DemoComponent from &#39;../components/DemoComponent&#39;\n\nexport default {\n  name: &#39;MyComponent&#39;,\n  components: {\n    DemoComponent\n  },\n  mixins: [],\n  props: {},\n  data () {\n    return {}\n  },\n  computed: {},\n  watch: {}\n  created () {},\n  mounted () {},\n  destroyed () {},\n  methods: {},\n}\n&lt;/script&gt;\n\n&lt;style lang=&quot;scss&quot; scoped&gt;\n#my-component {\n}\n&lt;/style&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-1-2-data" tabindex="-1"><a class="header-anchor" href="#_2-1-2-data" aria-hidden="true">#</a> 2.1.2 data</h4><p><strong>组件的 <code>data</code> 必须是一个函数。</strong></p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>// In a .vue file\nexport default {\n  data () {\n    return {\n      foo: &#39;bar&#39;\n    }\n  }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-1-3-prop" tabindex="-1"><a class="header-anchor" href="#_2-1-3-prop" aria-hidden="true">#</a> 2.1.3 prop</h4><p><strong>Prop 定义应该尽量详细。</strong></p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>export default {\n  props: {\n    status: {\n      type: String,\n      required: true,\n      validator: function (value) {\n        return [\n          &#39;syncing&#39;, \n          &#39;synced&#39;,\n          &#39;version-conflict&#39;,\n          &#39;error&#39;\n        ].indexOf(value) !== -1\n      }\n    }\n  }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-1-4-computed" tabindex="-1"><a class="header-anchor" href="#_2-1-4-computed" aria-hidden="true">#</a> 2.1.4 computed</h4><p><strong>应该把复杂计算属性分割为尽可能多的更简单的属性。</strong> 小的、专注的计算属性减少了信息使用时的假设性限制，所以需求变更时也用不着那么多重构了。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// bad\ncomputed: { \n  price: function () { \n    var basePrice = this.manufactureCost / (1 - this.profitMargin) \n    return ( \n      basePrice - \n      basePrice * (this.discountPercent || 0) \n    ) \n  } \n}\n\n// good\ncomputed: {\n  basePrice: function () {\n    return this.manufactureCost / (1 - this.profitMargin)\n  },\n  discount: function () {\n    return this.basePrice * (this.discountPercent || 0)\n  },\n  finalPrice: function () {\n    return this.basePrice - this.discount\n  }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-1-5-为-v-for-设置键值" tabindex="-1"><a class="header-anchor" href="#_2-1-5-为-v-for-设置键值" aria-hidden="true">#</a> 2.1.5 为 <code>v-for</code> 设置键值</h4><p><strong>在组件上必须用 <code>key</code> 搭配 <code>v-for</code></strong>，以便维护内部组件及其子树的状态。甚至在元素上维护可预测的行为，比如动画中的<strong>对象固化 (object constancy)</strong>[2]。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;ul&gt;\n  &lt;li\n    v-for=&quot;todo in todos&quot;\n    :key=&quot;todo.id&quot;&gt;\n      {{ todo.text }}\n  &lt;/li&gt;\n&lt;/ul&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-1-6-v-if-和-v-for-互斥" tabindex="-1"><a class="header-anchor" href="#_2-1-6-v-if-和-v-for-互斥" aria-hidden="true">#</a> 2.1.6 <code>v-if</code> 和 <code>v-for</code> 互斥</h4><p><strong>永远不要把 <code>v-if</code> 和 <code>v-for</code> 同时用在同一个元素上。</strong></p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- bad：控制台报错 --&gt;\n&lt;ul&gt;\n  &lt;li\n    v-for=&quot;user in users&quot;\n    v-if=&quot;shouldShowUsers&quot;\n    :key=&quot;user.id&quot;&gt;\n      {{ user.name }}\n  &lt;/li&gt;\n&lt;/ul&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>一般我们在两种常见的情况下会倾向于这样做：</p><ul><li>为了过滤一个列表中的项目 (比如 <code>v-for=&quot;user in users&quot; v-if=&quot;user.isActive&quot;</code>)。在这种情形下，请将 <code>users</code> 替换为一个计算属性 (比如 <code>activeUsers</code>)，让其返回过滤后的列表。</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>computed: {\n  activeUsers: function () {\n    return this.users.filter((user) =&gt; {\n      return user.isActive\n    })\n  }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;ul&gt;\n  &lt;li\n    v-for=&quot;user in activeUsers&quot;\n    :key=&quot;user.id&quot;&gt;\n      {{ user.name }}\n  &lt;/li&gt;\n&lt;/ul&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>为了避免渲染本应该被隐藏的列表 (比如 <code>v-for=&quot;user in users&quot; v-if=&quot;shouldShowUsers&quot;</code>)。这种情形下，请将 <code>v-if</code> 移动至容器元素上 (比如 <code>ul</code>, <code>ol</code>)。</li></ul><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- bad --&gt;\n&lt;ul&gt;\n  &lt;li\n    v-for=&quot;user in users&quot;\n    v-if=&quot;shouldShowUsers&quot;\n    :key=&quot;user.id&quot;&gt;\n      {{ user.name }}\n  &lt;/li&gt;\n&lt;/ul&gt;\n\n&lt;!-- good --&gt;\n&lt;ul v-if=&quot;shouldShowUsers&quot;&gt;\n  &lt;li\n    v-for=&quot;user in users&quot;\n    :key=&quot;user.id&quot;&gt;\n      {{ user.name }}\n  &lt;/li&gt;\n&lt;/ul&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-1-7-多个-attribute-的元素" tabindex="-1"><a class="header-anchor" href="#_2-1-7-多个-attribute-的元素" aria-hidden="true">#</a> 2.1.7 多个 attribute 的元素</h4><p><strong>多个 attribute 的元素应该分多行撰写，每个 attribute 一行。</strong></p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- bad --&gt;\n&lt;img src=&quot;https://vuejs.org/images/logo.png&quot; alt=&quot;Vue Logo&quot;&gt;\n&lt;MyComponent foo=&quot;a&quot; bar=&quot;b&quot; baz=&quot;c&quot;/&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- good --&gt;\n&lt;img\n  src=&quot;https://vuejs.org/images/logo.png&quot;\n  alt=&quot;Vue Logo&quot;&gt;\n\n&lt;MyComponent\n  foo=&quot;a&quot;\n  bar=&quot;b&quot;\n  baz=&quot;c&quot;/&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-1-8-模板中简单的表达式" tabindex="-1"><a class="header-anchor" href="#_2-1-8-模板中简单的表达式" aria-hidden="true">#</a> 2.1.8 模板中简单的表达式</h4><p><strong>组件模板应该只包含简单的表达式，复杂的表达式则应该重构为计算属性或方法。</strong></p><p>复杂表达式会让你的模板变得不那么声明式。我们应该尽量描述应该出现的<strong>是什么</strong>，而非<strong>如何</strong>计算那个值。而且计算属性和方法使得代码可以重用。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// bad\n{{\n  fullName.split(&#39; &#39;).map((word) =&gt; {\n    return word[0].toUpperCase() + word.slice(1)\n  }).join(&#39; &#39;)\n}}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>更好的做法：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>&lt;!-- 在模板中 --&gt;\n{{ normalizedFullName }}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// 复杂表达式已经移入一个计算属性\ncomputed: {\n  normalizedFullName: function () {\n    return this.fullName.split(&#39; &#39;).map(function (word) {\n      return word[0].toUpperCase() + word.slice(1)\n    }).join(&#39; &#39;)\n  }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-1-9-带引号的-attribute-值" tabindex="-1"><a class="header-anchor" href="#_2-1-9-带引号的-attribute-值" aria-hidden="true">#</a> 2.1.9 带引号的 attribute 值</h4><p><strong>非空 HTML 特性值应该始终带双引号。</strong></p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- bad --&gt;\n&lt;input type=text&gt;\n&lt;AppSidebar :style={width:sidebarWidth+&#39;px&#39;}&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- good --&gt;\n&lt;input type=&quot;text&quot;&gt;\n&lt;AppSidebar :style=&quot;{ width: sidebarWidth + &#39;px&#39; }&quot;&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-1-10-指令缩写" tabindex="-1"><a class="header-anchor" href="#_2-1-10-指令缩写" aria-hidden="true">#</a> 2.1.10 指令缩写</h4><ul><li><strong>用 <code>:</code> 表示 <code>v-bind:</code></strong></li><li><strong>用 <code>@</code> 表示 <code>v-on:</code></strong></li><li><strong>用 <code>#</code> 表示 <code>v-slot:</code></strong></li></ul><div class="language-vue ext-vue line-numbers-mode"><pre class="language-vue"><code>&lt;input\n  :value=&quot;newTodoText&quot;\n  :placeholder=&quot;newTodoInstructions&quot;&gt;\n\n&lt;input\n  @input=&quot;onInput&quot;\n  @focus=&quot;onFocus&quot;&gt;\n\n&lt;template #header&gt;\n  &lt;h1&gt;Here might be a page title&lt;/h1&gt;\n&lt;/template&gt;\n\n&lt;template #footer&gt;\n  &lt;p&gt;Here&#39;s some contact info&lt;/p&gt;\n&lt;/template&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-2-vue3" tabindex="-1"><a class="header-anchor" href="#_2-2-vue3" aria-hidden="true">#</a> 2.2 Vue3</h3><h3 id="_2-3-html" tabindex="-1"><a class="header-anchor" href="#_2-3-html" aria-hidden="true">#</a> 2.3 HTML</h3><h4 id="_2-3-1-文件模板" tabindex="-1"><a class="header-anchor" href="#_2-3-1-文件模板" aria-hidden="true">#</a> 2.3.1 文件模板</h4><p>HTML5 文件模板：</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!DOCTYPE html&gt;\n  &lt;html lang=&quot;zh-CN&quot;&gt;\n  &lt;head&gt;\n    &lt;meta charset=&quot;UTF-8&quot;&gt;\n    &lt;title&gt;HTML5标准模版&lt;/title&gt;\n  &lt;/head&gt;\n  &lt;body&gt;\n  &lt;/body&gt;\n&lt;/html&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>移动端：</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!DOCTYPE html&gt;\n&lt;html lang=&quot;zh-CN&quot;&gt;\n&lt;head&gt;\n    &lt;meta charset=&quot;UTF-8&quot;&gt;\n    &lt;meta name=&quot;viewport&quot;\n        content=&quot;width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no, shrink-to-fit=no&quot;&gt;\n    &lt;meta name=&quot;format-detection&quot; content=&quot;telephone=no&quot;&gt;\n    &lt;title&gt;移动端HTML模版&lt;/title&gt;\n\n    &lt;!-- S DNS预解析 --&gt;\n    &lt;link rel=&quot;dns-prefetch&quot; href=&quot;&quot;&gt;\n    &lt;!-- E DNS预解析 --&gt;\n\n    &lt;!-- S 线上样式页面片，开发请直接取消注释引用 --&gt;\n    &lt;!-- #include virtual=&quot;&quot; --&gt;\n    &lt;!-- E 线上样式页面片 --&gt;\n\n    &lt;!-- S 本地调试，根据开发模式选择调试方式，请开发删除 --&gt;\n    &lt;link rel=&quot;stylesheet&quot; href=&quot;css/index.css&quot;&gt;\n    &lt;!-- /本地调试方式 --&gt;\n\n    &lt;link rel=&quot;stylesheet&quot; href=&quot;http://srcPath/index.css&quot;&gt;\n    &lt;!-- /开发机调试方式 --&gt;\n    &lt;!-- E 本地调试 --&gt;\n\n&lt;/head&gt;\n&lt;body&gt;\n&lt;/body&gt;\n&lt;/html&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>PC 端：</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!DOCTYPE html&gt;\n&lt;html lang=&quot;zh-CN&quot;&gt;\n&lt;head&gt;\n    &lt;meta charset=&quot;UTF-8&quot;&gt;\n    &lt;meta name=&quot;keywords&quot; content=&quot;your keywords&quot;&gt;\n    &lt;meta name=&quot;description&quot; content=&quot;your description&quot;&gt;\n    &lt;meta name=&quot;author&quot; content=&quot;author,email address&quot;&gt;\n    &lt;meta name=&quot;robots&quot; content=&quot;index,follow&quot;&gt;\n    &lt;meta http-equiv=&quot;X-UA-Compatible&quot; content=&quot;IE=Edge,chrome=1&quot;&gt;\n    &lt;meta name=&quot;renderer&quot; content=&quot;ie-stand&quot;&gt;\n    &lt;title&gt;PC端HTML模版&lt;/title&gt;\n\n    &lt;!-- S DNS预解析 --&gt;\n    &lt;link rel=&quot;dns-prefetch&quot; href=&quot;&quot;&gt;\n    &lt;!-- E DNS预解析 --&gt;\n\n    &lt;!-- S 线上样式页面片，开发请直接取消注释引用 --&gt;\n    &lt;!-- #include virtual=&quot;&quot; --&gt;\n    &lt;!-- E 线上样式页面片 --&gt;\n\n    &lt;!-- S 本地调试，根据开发模式选择调试方式，请开发删除 --&gt;\n    &lt;link rel=&quot;stylesheet&quot; href=&quot;css/index.css&quot;&gt;\n    &lt;!-- /本地调试方式 --&gt;\n\n    &lt;link rel=&quot;stylesheet&quot; href=&quot;http://srcPath/index.css&quot;&gt;\n    &lt;!-- /开发机调试方式 --&gt;\n    &lt;!-- E 本地调试 --&gt;\n&lt;/head&gt;\n&lt;body&gt;\n&lt;/body&gt;\n&lt;/html&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-3-2-元素及标签闭合" tabindex="-1"><a class="header-anchor" href="#_2-3-2-元素及标签闭合" aria-hidden="true">#</a> 2.3.2 元素及标签闭合</h4><p>HTML 元素共有以下5种：</p><ul><li>空元素：area、base、br、col、command、embed、hr、img、input、keygen、link、meta、param、source、track、wbr</li><li>原始文本元素：script、style</li><li>RCDATA 元素：textarea、title</li><li>外来元素：来自 MathML 命名空间和 SVG 命名空间的元素</li><li>常规元素：其他 HTML 允许的元素都称为常规元素</li></ul><p>为了能让浏览器更好的解析代码以及能让代码具有更好的可读性，有如下约定：</p><ul><li>所有具有开始标签和结束标签的元素都要写上起止标签，某些允许省略开始标签或和束标签的元素亦都要写上。</li><li>空元素标签都不加 “/” 字符。</li></ul><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- good --&gt;\n&lt;div&gt;\n    &lt;h1&gt;我是h1标题&lt;/h1&gt;\n    &lt;p&gt;我是一段文字，我有始有终，浏览器能正确解析&lt;/p&gt;\n&lt;/div&gt;\n \n&lt;br data-tomark-pass&gt;\n\n&lt;!-- bad --&gt;\n&lt;div&gt;\n    &lt;h1&gt;我是h1标题&lt;/h1&gt;\n    &lt;p&gt;我是一段文字，我有始无终，浏览器亦能正确解析\n&lt;/div&gt;\n\n&lt;br/&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-2-3-代码嵌套" tabindex="-1"><a class="header-anchor" href="#_2-2-3-代码嵌套" aria-hidden="true">#</a> 2.2.3 代码嵌套</h4><p>元素嵌套规范，每个块状元素独立一行，内联元素可选。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- good --&gt;\n&lt;div&gt;\n    &lt;h1&gt;&lt;/h1&gt;\n    &lt;p&gt;&lt;/p&gt;\n&lt;/div&gt; \n&lt;p&gt;&lt;span&gt;&lt;/span&gt;&lt;span&gt;&lt;/span&gt;&lt;/p&gt;\n\n&lt;!-- bad --&gt;\n&lt;div&gt;\n    &lt;h1&gt;&lt;/h1&gt;&lt;p&gt;&lt;/p&gt;\n&lt;/div&gt; \n&lt;p&gt; \n    &lt;span&gt;&lt;/span&gt;\n    &lt;span&gt;&lt;/span&gt;\n&lt;/p&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>段落元素与标题元素只能嵌套内联元素。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- good --&gt;\n&lt;h1&gt;&lt;span&gt;&lt;/span&gt;&lt;/h1&gt;\n&lt;p&gt;&lt;span&gt;&lt;/span&gt;&lt;span&gt;&lt;/span&gt;&lt;/p&gt;\n\n&lt;!-- bad --&gt;\n&lt;h1&gt;&lt;div&gt;&lt;/div&gt;&lt;/h1&gt;\n&lt;p&gt;&lt;div&gt;&lt;/div&gt;&lt;div&gt;&lt;/div&gt;&lt;/p&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-4-css" tabindex="-1"><a class="header-anchor" href="#_2-4-css" aria-hidden="true">#</a> 2.4 CSS</h3><h4 id="_2-4-1-样式文件" tabindex="-1"><a class="header-anchor" href="#_2-4-1-样式文件" aria-hidden="true">#</a> 2.4.1 样式文件</h4><p>样式文件必须写上 <code>@charset</code> 规则，并且一定要在样式文件的第一行首个字符位置开始写，编码名用 <code>“UTF-8”</code>。</p><ul><li>推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>@charset &quot;UTF-8&quot;;\n.jdc {}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>/* @charset规则不在文件首行首个字符开始 */\n@charset &quot;UTF-8&quot;;\n.jdc {}\n\n/* @charset规则没有用小写 */\n@CHARSET &quot;UTF-8&quot;;\n.jdc {}\n\n/* 无@charset规则 */\n.jdc {}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-4-2-代码格式化" tabindex="-1"><a class="header-anchor" href="#_2-4-2-代码格式化" aria-hidden="true">#</a> 2.4.2 代码格式化</h4><p>样式书写一般有两种：一种是紧凑格式 （Compact），一种是展开格式（Expanded）。</p><ul><li>推荐：展开格式（Expanded）</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  display: block;\n  width: 50px;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：紧凑格式 （Compact）</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc { display: block; width: 50px;}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="_2-4-3-代码大小写" tabindex="-1"><a class="header-anchor" href="#_2-4-3-代码大小写" aria-hidden="true">#</a> 2.4.3 代码大小写</h4><p>样式选择器，属性名，属性值关键字全部使用小写字母书写，属性字符串允许使用大小写。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  display: block;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.JDC {\n  DISPLAY: BLOCK;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-4-4-代码易读性" tabindex="-1"><a class="header-anchor" href="#_2-4-4-代码易读性" aria-hidden="true">#</a> 2.4.4 代码易读性</h4><ol><li>左括号与类名之间一个空格，冒号与属性值之间一个空格。</li></ol><ul><li>推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  width: 100%;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc{\n  width:100%;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol><li>逗号分隔的取值，逗号之后一个空格。</li></ol><ul><li>推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  box-shadow: 1px 1px 1px #333, 2px 2px 2px #ccc;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  box-shadow: 1px 1px 1px #333,2px 2px 2px #ccc;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol><li>为单个 CSS 选择器或新声明开启新行。</li></ol><ul><li>推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc, .jdc_logo, .jdc_hd {\n  color: #ff0;\n}\n\n.nav{\n  color: #fff;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc, .jdc_logo, .jdc_hd {\n  color: #ff0;\n}.nav{\n  color: #fff;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol><li>颜色值 <code>rgb()</code> <code>rgba()</code> <code>hsl()</code> <code>hsla()</code> <code>rect()</code> 中不需有空格，且取值不要带有不必要的 0。</li></ol><ul><li>推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  color: rgba(255,255,255,.5);\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  color: rgba( 255, 255, 255, 0.5 );\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol><li>属性值十六进制数值能用简写的尽量用简写。</li></ol><ul><li>推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  color: #fff;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  color: #ffffff;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol><li>不要为 <code>0</code> 指明单位。</li></ol><ul><li>推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  margin: 0 10px;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>.jdc {\n  margin: 0px 10px;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-4-5-属性值引号" tabindex="-1"><a class="header-anchor" href="#_2-4-5-属性值引号" aria-hidden="true">#</a> 2.4.5 属性值引号</h4><p>CSS 属性值需要用到引号时，统一使用单引号。</p><ul><li>推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  font-family: &#39;Hiragino Sans GB&#39;;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  font-family: &quot;Hiragino Sans GB&quot;;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-4-6-属性书写建议" tabindex="-1"><a class="header-anchor" href="#_2-4-6-属性书写建议" aria-hidden="true">#</a> 2.4.6 属性书写建议</h4><p>建议遵循以下顺序：</p><ol><li>布局定位属性：display / position / float / clear / visibility / overflow</li><li>自身属性：width / height / margin / padding / border / background</li><li>文本属性：color / font / text-decoration / text-align / vertical-align / white- space / break-word</li><li>其他属性（CSS3）：content / cursor / border-radius / box-shadow / text-shadow / background: linear-gradient …</li></ol><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>.jdc {\n  display: block;\n  position: relative;\n  float: left;\n  width: 100px;\n  height: 100px;\n  margin: 0 10px;\n  padding: 20px 0;\n  font-family: Arial, &#39;Helvetica Neue&#39;, Helvetica, sans-serif;\n  color: #333;\n  background: rgba(0,0,0,.5);\n  -webkit-border-radius: 10px;\n  -moz-border-radius: 10px;\n  -o-border-radius: 10px;\n  -ms-border-radius: 10px;\n  border-radius: 10px;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-4-7-css3-浏览器私有前缀" tabindex="-1"><a class="header-anchor" href="#_2-4-7-css3-浏览器私有前缀" aria-hidden="true">#</a> 2.4.7 CSS3 浏览器私有前缀</h4><p>CSS3 浏览器私有前缀在前，标准前缀在后。</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>.jdc {\n  -webkit-border-radius: 10px;\n  -moz-border-radius: 10px;\n  -o-border-radius: 10px;\n  -ms-border-radius: 10px;\n  border-radius: 10px;\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-4-javascript" tabindex="-1"><a class="header-anchor" href="#_2-4-javascript" aria-hidden="true">#</a> 2.4 JavaScript</h3><h4 id="_2-4-1-单行代码块" tabindex="-1"><a class="header-anchor" href="#_2-4-1-单行代码块" aria-hidden="true">#</a> 2.4.1 单行代码块</h4><p>在单行代码块中使用空格。</p><ul><li>不推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>function foo () {return true}\nif (foo) {bar = 0}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>function foo () { return true }\nif (foo) { bar = 0 }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-4-2-大括号风格" tabindex="-1"><a class="header-anchor" href="#_2-4-2-大括号风格" aria-hidden="true">#</a> 2.4.2 大括号风格</h4><p>在编程过程中，大括号风格与缩进风格紧密联系，用来描述大括号相对代码块位置的方法有很多。在 JavaScript 中，主要有三种风格，如下：</p><ul><li><strong>【推荐】One True Brace Style</strong></li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>if (foo) {\n  bar()\n} else {\n  baz()\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><strong>Stroustrup</strong></li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>if (foo) {\n  bar()\n}\nelse {\n  baz()\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><strong>Allman</strong></li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>if (foo)\n{\n  bar()\n}\nelse\n{\n  baz()\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-4-3-代码中的空格" tabindex="-1"><a class="header-anchor" href="#_2-4-3-代码中的空格" aria-hidden="true">#</a> 2.4.3 代码中的空格</h4><p>1.逗号前后的空格可以提高代码的可读性，团队约定在逗号后面使用空格，逗号前面不加空格。</p><ul><li>推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>var foo = 1, bar = 2\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>var foo = 1,bar = 2\n\nvar foo = 1 , bar = 2\n\nvar foo = 1 ,bar = 2\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>2.对象字面量的键和值之间不能存在空格，且要求对象字面量的冒号和值之间存在一个空格。</p><ul><li>推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>var obj = { &#39;foo&#39;: &#39;haha&#39; }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>var obj = { &#39;foo&#39; : &#39;haha&#39; }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>3.代码块前要添加空格。</p><ul><li>推荐：</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>if (a) {\n  b()\n}\n\nfunction a () {}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>4.函数声明括号前要加空格。</p><ul><li>推荐：</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>function func (x) {\n  // ...\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>function func(x) {\n  // ...\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>5.在函数调用时，禁止使用空格。</p><ul><li>推荐：</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>fn()\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>fn ()\n\nfn\n()\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>6.在操作符前后都需要添加空格。</p><ul><li>推荐：</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>var sum = 1 + 2\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>var sum = 1+2\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="三、注释规范" tabindex="-1"><a class="header-anchor" href="#三、注释规范" aria-hidden="true">#</a> 三、注释规范</h2><p><strong>注释的目的：</strong></p><ul><li><strong>提高代码的可读性，从而提高代码的可维护性</strong></li></ul><p><strong>注释的原则：</strong></p><ul><li><strong>如无必要，勿增注释 ( As short as possible )</strong></li><li><strong>如有必要，尽量详尽 ( As long as necessary )</strong></li></ul><h3 id="_3-1-html-文件注释" tabindex="-1"><a class="header-anchor" href="#_3-1-html-文件注释" aria-hidden="true">#</a> 3.1 HTML 文件注释</h3><h4 id="_3-1-1-单行注释" tabindex="-1"><a class="header-anchor" href="#_3-1-1-单行注释" aria-hidden="true">#</a> 3.1.1 单行注释</h4><p><strong>一般用于简单的描述，如某些状态描述、属性描述等。</strong></p><p>注释内容前后各一个空格字符，注释位于要注释代码的上面，单独占一行。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- Comment Text --&gt;\n&lt;div&gt;...&lt;/div&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐</li></ul><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;div&gt;...&lt;/div&gt;&lt;!-- Comment Text --&gt;\n\n&lt;div&gt;&lt;!-- Comment Text --&gt;\n  ...\n&lt;/div&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-1-2-模块注释" tabindex="-1"><a class="header-anchor" href="#_3-1-2-模块注释" aria-hidden="true">#</a> 3.1.2 模块注释</h4><p><strong>一般用于描述模块的名称以及模块开始与结束的位置。</strong></p><p>注释内容前后各一个空格字符， <code>&lt;!-- S Comment Text \\--&gt;</code>表示模块开始， <code>&lt;!-- E Comment Text \\--&gt;</code>表示模块结束，模块与模块之间相隔一行。</p><ul><li>推荐：</li></ul><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- S Comment Text A --&gt; \n&lt;div class=&quot;mod_a&quot;&gt;\n  ...\n&lt;/div&gt;\n&lt;!-- E Comment Text A --&gt;\n \n&lt;!-- S Comment Text B --&gt; \n&lt;div class=&quot;mod_b&quot;&gt;\n  ...\n&lt;/div&gt;\n&lt;!-- E Comment Text B --&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐</li></ul><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- S Comment Text A --&gt;\n&lt;div class=&quot;mod_a&quot;&gt;\n  ...\n&lt;/div&gt;\n&lt;!-- E Comment Text A --&gt;\n&lt;!-- S Comment Text B --&gt; \n&lt;div class=&quot;mod_b&quot;&gt;\n  ...\n&lt;/div&gt;\n&lt;!-- E Comment Text B --&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-1-3-嵌套模块注释" tabindex="-1"><a class="header-anchor" href="#_3-1-3-嵌套模块注释" aria-hidden="true">#</a> 3.1.3 嵌套模块注释</h4><p>当模块注释内再出现模块注释的时候，为了突出主要模块，嵌套模块不再使用。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- S Comment Text --&gt;\n&lt;!-- E Comment Text --&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>而改用</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- /Comment Text --&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>注释写在模块结尾标签底部，单独一行。</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code>&lt;!-- S Comment Text A --&gt;\n&lt;div class=&quot;mod_a&quot;&gt;\n  \n    &lt;div class=&quot;mod_b&quot;&gt;\n        ...\n    &lt;/div&gt;\n    &lt;!-- /mod_b --&gt;\n     \n    &lt;div class=&quot;mod_c&quot;&gt;\n     ...\n    &lt;/div&gt;\n    &lt;!-- /mod_c --&gt;\n  \n&lt;/div&gt;\n&lt;!-- E Comment Text A --&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-2-css-文件注释" tabindex="-1"><a class="header-anchor" href="#_3-2-css-文件注释" aria-hidden="true">#</a> 3.2 CSS 文件注释</h3><h4 id="_3-2-1-单行注释" tabindex="-1"><a class="header-anchor" href="#_3-2-1-单行注释" aria-hidden="true">#</a> 3.2.1 单行注释</h4><p>注释内容第一个字符和最后一个字符都是一个空格字符，单独占一行，行与行之间相隔一行。</p><ul><li>推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>/* Comment Text */ \n.jdc {} \n\n/* Comment Text */ \n.jdc {}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>/*Comment Text*/\n.jdc {\n  display: block;\n}\n\n.jdc {\n  display: block;/*Comment Text*/\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-2-2-模块注释" tabindex="-1"><a class="header-anchor" href="#_3-2-2-模块注释" aria-hidden="true">#</a> 3.2.2 模块注释</h4><p>注释内容第一个字符和最后一个字符都是一个空格字符，<code>/*</code> 与 模块信息描述占一行，多个横线分隔符 <code>-</code> 与 <code>*/</code> 占一行，行与行之间相隔两行。</p><ul><li>推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>/* Module A\n---------------------------------------------------------------- */\n.mod_a {}\n\n\n/* Module B\n---------------------------------------------------------------- */\n.mod_b {}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>/* Module A ---------------------------------------------------- */\n.mod_a {}\n/* Module B ---------------------------------------------------- */\n.mod_b {}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-2-3-文件注释" tabindex="-1"><a class="header-anchor" href="#_3-2-3-文件注释" aria-hidden="true">#</a> 3.2.3 文件注释</h4><p>在样式文件编码声明 <code>@charset</code> 语句下面注明页面名称、作者、创建日期等信息。</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code>@charset &quot;UTF-8&quot;;\n/**\n * @desc File Info\n * @author Author Name\n * @date 2015-10-10\n */\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-3-javascript-文件注释" tabindex="-1"><a class="header-anchor" href="#_3-3-javascript-文件注释" aria-hidden="true">#</a> 3.3 JavaScript 文件注释</h3><h4 id="_3-3-1-单行注释" tabindex="-1"><a class="header-anchor" href="#_3-3-1-单行注释" aria-hidden="true">#</a> 3.3.1 单行注释</h4><p>单行注释使用 <code>//</code>，注释应单独一行写在被注释对象的上方，不要追加在某条语句的后面。</p><ul><li>推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// is current tab\nconst active = true\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>const active = true // is current tab\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>注释行的上方需要有一个空行（<strong>除非注释行上方是一个块的顶部</strong>），以增加可读性。</p><ul><li>推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>function getType () {  \n  console.log(&#39;fetching type...&#39;)\n  \n  // set the default type to &#39;no type&#39;\n  const type = this.type || &#39;no type&#39;\n  return type\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// 注释行上面是一个块的顶部时不需要空行\nfunction getType () {  \n  // set the default type to &#39;no type&#39;\n  const type = this.type || &#39;no type&#39;   \n  return type\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>function getType () {  \n  console.log(&#39;fetching type...&#39;)\n  // set the default type to &#39;no type&#39;\n  const type = this.type || &#39;no type&#39;\n  return type\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-3-2-多行注释" tabindex="-1"><a class="header-anchor" href="#_3-3-2-多行注释" aria-hidden="true">#</a> 3.3.2 多行注释</h4><p>多行注释使用 <code>/** ... */</code>，而不是多行的 <code>//</code>。</p><ul><li>推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>/**\n * make() returns a new element\n * based on the passed-in tag name\n */\nfunction make (tag) {\n  // ...\n\n  return element\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// make() returns a new element\n// based on the passed in tag name\nfunction make (tag) {\n  // ...\n\n  return element\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-3-3-注释空格" tabindex="-1"><a class="header-anchor" href="#_3-3-3-注释空格" aria-hidden="true">#</a> 3.3.3 注释空格</h4><p>注释内容和注释符之间需要有一个空格，以增加可读性。eslint: <code>spaced-comment</code>。</p><ul><li>推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>// is current tab\nconst active = true\n\n/**\n * make() returns a new element\n * based on the passed-in tag name\n */\nfunction make(tag) {  \n  // ...\n\n  return element\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不推荐：</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>//is current tab\nconst active = true\n\n/**\n *make() returns a new element\n *based on the passed-in tag name\n */\nfunction make(tag) {  \n  // ...\n\n  return element\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-3-4-特殊标记" tabindex="-1"><a class="header-anchor" href="#_3-3-4-特殊标记" aria-hidden="true">#</a> 3.3.4 特殊标记</h4><p>有时我们发现某个可能的 bug，但因为一些原因还没法修复；或者某个地方还有一些待完成的功能，这时我们需要使用相应的特殊标记注释来告知未来的自己或合作者。常用的特殊标记有两种：</p><ul><li><code>// FIXME</code> : 说明问题是什么</li><li><code>// TODO</code> : 说明还要做什么或者问题的解决方案</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>class Calculator extends Abacus {\n  constructor () {\n    super ()\n\n      // FIXME: shouldn’t use a global here\n      total = 0\n\n      // TODO: total should be configurable by an options param\n      this.total = 0\n  }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-3-5-文档类注释" tabindex="-1"><a class="header-anchor" href="#_3-3-5-文档类注释" aria-hidden="true">#</a> 3.3.5 文档类注释</h4><p>文档类注释，如函数、类、文件、事件等；都使用 jsdoc 规范。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>/**\n * Book类，代表一个书本.\n * @constructor\n * @param {string} title - 书本的标题.\n * @param {string} author - 书本的作者.\n */\nfunction Book (title, author) {\n  this.title = title\n  this.author = author\n}\n\nBook.prototype = {\n  /**\n   * 获取书本的标题\n   * @returns {string|*}\n   */\n  getTitle: function () {\n    return this.title\n  },\n  /**\n   * 设置书本的页数\n   * @param pageNum {number} 页数\n   */\n  setPageNum: function (pageNum) {\n    this.pageNum=pageNum\n  }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-3-6-注释工具" tabindex="-1"><a class="header-anchor" href="#_3-3-6-注释工具" aria-hidden="true">#</a> 3.3.6 注释工具</h4><p><code>ESLint</code> 是当下最流行的 JS 代码检查工具，<code>ESLint</code> 中有一些注释相关的规则，用户可选择开启：</p><ul><li><p><code>valid-jsdoc</code></p></li><li><p><code>require-jsdoc</code></p></li><li><p><code>no-warning-comments</code></p></li><li><p><code>capitalized-comments</code></p></li><li><p><code>line-comment-position</code></p></li><li><p><code>lines-around-comment</code></p></li><li><p><code>multiline-comment-style</code></p></li><li><p><code>no-inline-comments</code></p></li><li><p><code>spaced-comment</code></p></li><li></li></ul><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> 参考资料</h2><p>https://mp.weixin.qq.com/s/vaNUbIUSkvPZbnt1ZDgTDg</p>',339),s={},d=(0,n(63243).Z)(s,[["render",function(e,i){return l}]])},63243:(e,i)=>{i.Z=(e,i)=>{const n=e.__vccOpts||e;for(const[e,l]of i)n[e]=l;return n}}}]);